mapper.select:
select t.tip_num, t.category, c.name as category_name, t.content, t.writer, t.member_id, t.guest_password, t.reg_date, t.recommend_count from one_line_strategy t join one_line_strategy_category c on t.category = c.code where
and t.category = #{category}
order by t.reg_date desc, t.tip_num desc limit #{page.postBeginPoint}, #{page.displayPostLimit}

select tip_num, category, content, writer, member_id, guest_password, reg_date, recommend_count
from one_line_strategy
where tip_num = #{tipNum}

mapper.update:
update one_line_strategy
set recommend_count = recommend_count + 1
where tip_num = #{tipNum}
